function test_multicall() public {
    bytes[] memory calls = new bytes[](2);
    calls[0] = abi.encodeWithSelector(MockMulticall(multicall).functionThatReturnsTuple.selector, 10, 20);
    calls[1] = abi.encodeWithSelector(MockMulticall(multicall).functionThatReturnsTuple.selector, 1, 2);

    bytes[] memory results = multicall.multicall(calls);

    (uint256 a, uint256 b) = abi.decode(results[0], (uint256, uint256));
    assertEq(a, 10);
    assertEq(b, 20);

    (a, b) = abi.decode(results[1], (uint256, uint256));
    assertEq(a, 1);
    assertEq(b, 2);
}

function flashLoan(
  IERC3156FlashBorrower receiver,
  address token,
  uint256 amount,
  bytes calldata data
) external override nonReentrant returns (bool) {
  if (token != address(this)) {
    revert IllegalArgument();
  }

  if (amount > maxFlashLoan(token)) {
    revert IllegalArgument();
  }

  uint256 fee = flashFee(token, amount);

  _mint(address(receiver), amount);

  if (receiver.onFlashLoan(msg.sender, token, amount, fee, data) != CALLBACK_SUCCESS) {
    revert IllegalState();
  }

  _burn(address(receiver), amount + fee); // Will throw error if not enough to burn

  return true;
}

function getExpectedExchange(address factory, address token0, address token1, uint24 fee0, address token2, uint24 fee1, uint256 amount) external returns (uint256) {
    IUniswapV3Factory uniswapFactory = IUniswapV3Factory(factory);

    IUniswapV3Pool pool = IUniswapV3Pool(uniswapFactory.getPool(token0, token1, fee0));
    (uint160 sqrtPriceX96,,,,,,) =  pool.slot0();
    uint256 price0 = uint(sqrtPriceX96) * (uint(sqrtPriceX96)) * (1e18) >> (96 * 2);

    if (token2 == address(0)) return amount * price0 / 1e18;

    pool = IUniswapV3Pool(uniswapFactory.getPool(token1, token2, fee1));
    ( sqrtPriceX96,,,,,,) =  pool.slot0();
    uint256 price1 = uint(sqrtPriceX96) * (uint(sqrtPriceX96)) * (1e18) >> (96 * 2);

    return amount * price0 / price1;
}

