function _split(string memory input, string memory delimiter) private pure returns (string[] memory) {
    bytes memory inputBytes = bytes(input);
    bytes memory delimiterBytes = bytes(delimiter);

    uint256 partsCount = 1;

    for (uint256 i = 0; i < inputBytes.length; i++) {
        if (inputBytes[i] == delimiterBytes[0]) {
            partsCount++;
        }
    }

    string[] memory parts = new string[](partsCount);

    uint256 partIndex = 0;
    uint256 startIndex = 0;

    for (uint256 i = 0; i < inputBytes.length; i++) {
        if (inputBytes[i] == delimiterBytes[0]) {
            parts[partIndex] = _substring(input, startIndex, i);
            startIndex = i + 1;
            partIndex++;
        }
    }

    parts[partIndex] = _substring(input, startIndex, inputBytes.length);

    return parts;
}

function _fulfillDeposit(uint256 assets, uint256 shares, address controller) internal virtual {
    uint256 pendingAssets = pendingDepositRequest(0, controller);
    require(assets <= pendingAssets, ERC7540DepositInsufficientPendingAssets(assets, pendingAssets));

    _deposits[controller].pendingAssets -= assets;
    _deposits[controller].claimableAssets += assets;
    _deposits[controller].claimableShares += shares;

    if (_depositShareOrigin() != address(0)) {
        _mintSharesOnDepositFulfill(assets, shares);
    }

    emit DepositClaimable(controller, 0, assets, shares);
}

function _propose(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    string memory description,
    address proposer
) internal virtual override returns (uint256) {
    GovernorSequentialProposalIdStorage storage $ = _getGovernorSequentialProposalIdStorage();
    uint256 proposalHash = hashProposal(targets, values, calldatas, keccak256(bytes(description)));
    uint256 storedProposalId = $._proposalIds[proposalHash];
    if (storedProposalId == 0) {
        $._proposalIds[proposalHash] = ++$._latestProposalId;
    }
    return super._propose(targets, values, calldatas, description, proposer);
}

function setFeeds(
  string[] memory feedIds,
  string[] memory feedNames,
  int192[] memory deviationPercentagePPMs,
  uint32[] memory stalenessSeconds
) public onlyOwner feedsAreValid(feedIds, feedNames, deviationPercentagePPMs, stalenessSeconds) {
  // Clear prior feeds.
  for (uint256 i = 0; i < s_feeds.length; i++) {
    s_feedMapping[s_feeds[i]].active = false;
  }

  // Assign new feeds.
  for (uint256 i = 0; i < feedIds.length; i++) {
    string memory feedId = feedIds[i];
    if (s_feedMapping[feedId].active) {
      revert DuplicateFeed(feedId);
    }
    _updateFeed(feedId, feedNames[i], deviationPercentagePPMs[i], stalenessSeconds[i]);
    s_feedMapping[feedId].active = true;
  }
  s_feeds = feedIds;
}

function estimateZapInInitial(address from, uint256 fromAmount) external view returns (uint256 tokensToReceive, uint256 mintTokenTaxAmount) {
    uint256 mintAmount;

    if (from == MINT_CONTRACT) {
        mintAmount = fromAmount;
    } else {
        address[] memory path = _getPathToMint(from);

        mintAmount = PANCAKE_ROUTER.getAmountsOut(fromAmount, path)[path.length - 1];
    }

    uint256 taxAmount = mintAmount * BUY_TAX / MAX_TAX;
    uint256 newSupply = Math.floorSqrt(2 * 1e18 * (mintAmount - taxAmount));

    return (newSupply, taxAmount);
}

function _swap(PoolKey memory poolKey, bool zeroForOne, int256 amountSpecified, bytes calldata hookData)
        internal
        returns (BalanceDelta swapDelta)
    {
        swapDelta = poolManager.swap(
            poolKey,
            SwapParams({
                zeroForOne: zeroForOne,
                amountSpecified: amountSpecified,
                sqrtPriceLimitX96: zeroForOne ? TickMath.MIN_SQRT_PRICE + 1 : TickMath.MAX_SQRT_PRICE - 1
            }),
            hookData
        );

        // Check that the pool was not illiquid.
        int128 amountSpecifiedActual = (zeroForOne == (amountSpecified < 0)) ? swapDelta.amount0() : swapDelta.amount1();
        if (amountSpecifiedActual != amountSpecified) {
            revert NotEnoughLiquidity(poolKey.toId());
        }
    }

