function wrap(
    uint256 amount,
    address recipient
) external onlyAlchemist returns (uint256) {
    SafeERC20.safeTransferFrom(underlyingToken, msg.sender, address(this), amount);
    SafeERC20.safeApprove(underlyingToken, token, amount);

    uint256 startingBalance = IERC20(token).balanceOf(address(this));

    uint256 error;
    if ((error = ICERC20(token).mint(amount)) != NO_ERROR) {
        revert FuseError(error);
    }

    uint256 endingBalance = IERC20(token).balanceOf(address(this));
    uint256 mintedAmount = endingBalance - startingBalance;

    SafeERC20.safeTransfer(token, recipient, mintedAmount);

    return mintedAmount;
}

function _getCurrentLimit(
  uint256 _currentLimit,
  uint256 _maxLimit,
  uint256 _timestamp,
  uint256 _ratePerSecond
) internal view returns (uint256 _limit) {
  _limit = _currentLimit;
  if (_limit == _maxLimit) {
    return _limit;
  } else if (_timestamp + _DURATION <= block.timestamp) {
    _limit = _maxLimit;
  } else if (_timestamp + _DURATION > block.timestamp) {
    uint256 _timePassed = block.timestamp - _timestamp;
    uint256 _calculatedLimit = _limit + (_timePassed * _ratePerSecond);
    _limit = _calculatedLimit > _maxLimit ? _maxLimit : _calculatedLimit;
  }
}

function permit(
  address owner,
  address spender,
  uint256 value,
  uint256 deadline,
  uint8 v,
  bytes32 r,
  bytes32 s,
  uint256 chainId
) external {
  require(owner != address(0), 'INVALID_OWNER');
  //solium-disable-next-line
  require(block.timestamp <= deadline, 'INVALID_EXPIRATION');
  uint256 currentValidNonce = _nonces[owner];
  bytes32 digest =
    keccak256(
      abi.encodePacked(
        '\x19\x01',
        getDomainSeparator(chainId),
        keccak256(abi.encode(PERMIT_TYPEHASH, owner, spender, value, currentValidNonce, deadline))
      )
    );
  require(owner == ecrecover(digest, v, r, s), 'INVALID_SIGNATURE');
  _nonces[owner] = currentValidNonce + 1;
  _approve(owner, spender, value);
}

function withdraw(
  uint256 _shares,
  address _recipient,
  uint256 maxSlippage
) public returns (uint256) {
  // mirror real vault behavior
  if (_shares == type(uint256).max) {
    _shares = balanceOf(msg.sender);
  }
  uint256 _r = (balance() * _shares) / totalSupply();
  _burn(msg.sender, _shares);

  // apply mock slippage
  uint256 withdrawnAmt = _r - (_r * forcedSlippage) / PERCENT_RESOLUTION;
  require(withdrawnAmt >= _r - (_r * maxSlippage) / PERCENT_RESOLUTION, "too much slippage");


  TokenUtils.safeTransfer(token, _recipient, _r);
  return _r;
}

function setRewardWeights(uint256[] calldata _rewardWeights) external onlyGovernance {
  require(_rewardWeights.length == _pools.length(), "StakingPools: weights length mismatch");

  _updatePools();

  uint256 _totalRewardWeight = _ctx.totalRewardWeight;
  for (uint256 _poolId = 0; _poolId < _pools.length(); _poolId++) {
    Pool.Data storage _pool = _pools.get(_poolId);

    uint256 _currentRewardWeight = _pool.rewardWeight;
    if (_currentRewardWeight == _rewardWeights[_poolId]) {
      continue;
    }

    _totalRewardWeight = _totalRewardWeight - _currentRewardWeight + _rewardWeights[_poolId];
    _pool.rewardWeight = _rewardWeights[_poolId];

    emit PoolRewardWeightUpdated(_poolId, _rewardWeights[_poolId]);
  }

  _ctx.totalRewardWeight = _totalRewardWeight;
}

function registerAsset(
    address underlyingToken,
    address _transmuter
) external override onlyAdmin {
    if (!IAlchemistV2(alchemist).isSupportedUnderlyingToken(underlyingToken)) {
        revert IllegalState();
    }

    // only add to the array if not already contained in it
    for (uint256 i = 0; i < registeredUnderlyings.length; ++i) {
        if (registeredUnderlyings[i] == underlyingToken) {
            revert IllegalState();
        }
    }

    if (ITransmuterV2(_transmuter).underlyingToken() != underlyingToken) {
        revert IllegalArgument();
    }

    transmuter[underlyingToken] = _transmuter;
    registeredUnderlyings.push(underlyingToken);
    TokenUtils.safeApprove(underlyingToken, alchemist, type(uint256).max);
    emit RegisterAsset(underlyingToken, _transmuter);
}

