    arbOwner.setPerBatchGasCharge(newPerBatchGasCharge);
    arbOwner.setAmortizedCostCapBips(0);

    // verify
    ArbGasInfo arbGasInfo = ArbGasInfo(0x000000000000000000000000000000000000006C);
