function setParams(
    IL2ArbitrumGoverner gov,
    IArbitrumTimelock timelock,
    uint256 vd,
    uint256 vp,
    uint256 tp
) internal {
    bytes memory votingDelayData =
        abi.encodeWithSelector(IL2ArbitrumGoverner.setVotingDelay.selector, vd);
    gov.relay(address(gov), 0, votingDelayData);
    require(gov.votingDelay() == vd, "ArbGoerliSetInitialGovParamsAction: Voting delay not set");

    bytes memory votingPeriodData =
        abi.encodeWithSelector(IL2ArbitrumGoverner.setVotingPeriod.selector, vp);
    gov.relay(address(gov), 0, votingPeriodData);
    require(
        gov.votingPeriod() == vp, "ArbGoerliSetInitialGovParamsAction: Voting period not set"
    );

    timelock.updateDelay(tp);
    require(timelock.getMinDelay() == tp, "ArbGoerliSetInitialGovParamsAction: Timelock delay");
}

function contains(string memory str, string memory substr) internal pure returns (bool) {
    bytes memory strBytes = bytes(str);
    bytes memory substrBytes = bytes(substr);
    if (strBytes.length < substrBytes.length || strBytes.length == 0) {
        return false;
    }

    for (uint256 i = 0; i <= strBytes.length - substrBytes.length; i++) {
        bool isEqual = true;
        for (uint256 j = 0; j < substrBytes.length; j++) {
            if (strBytes[i + j] != substrBytes[j]) {
                isEqual = false;
                break;
            }
        }
        if (isEqual) return true;
    }
    return false;
}

function areUniqueAddressArraysEqual(address[] memory array1, address[] memory array2)
        public
        pure
        returns (bool)
    {
        if (array1.length != array2.length) {
            return false;
        }

        for (uint256 i = 0; i < array1.length; i++) {
            bool found = false;
            for (uint256 j = 0; j < array2.length; j++) {
                if (array1[i] == array2[j]) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                return false;
            }
        }

        return true;
    }

function _checkCorrectSigners(address[] memory signers_) internal view virtual {
    ABridgeStorage storage $ = _getABridgeStorage();

    uint256 bitMap_;

    for (uint256 i = 0; i < signers_.length; ++i) {
        address signer_ = signers_[i];

        if (!$.signers.contains(signer_)) revert InvalidSigner(signer_);

        // get the topmost byte for bloom filtering
        uint256 bitKey_ = 2 ** (uint256(uint160(signer_)) >> 152);

        if (bitMap_ & bitKey_ != 0) revert DuplicateSigner(signer_);

        bitMap_ |= bitKey_;
    }

    if (signers_.length < $.signaturesThreshold) revert ThresholdNotMet(signers_.length);
}

function computeCreate3Address(bytes32 salt, address deployer) public pure returns (address computedAddress) {
    assembly ("memory-safe") {
        let ptr := mload(0x40)
        mstore(0x00, deployer)
        mstore8(0x0b, 0xff)
        mstore(0x20, salt)
        mstore(
            0x40,
            hex"21_c3_5d_be_1b_34_4a_24_88_cf_33_21_d6_ce_54_2f_8e_9f_30_55_44_ff_09_e4_99_3a_62_31_9a_49_7c_1f"
        )
        mstore(0x14, keccak256(0x0b, 0x55))
        mstore(0x40, ptr)
        mstore(0x00, 0xd694)
        mstore8(0x34, 0x01)
